INSERT INTO t_p83689144_profix_network_admin.site_content (key, value) VALUES
('partner.atol.hero_title', 'АТОЛ — кассовое оборудование №1 в России'),
('partner.atol.hero_desc', 'Ведущий российский производитель контрольно-кассовой техники. Официальный партнёр АТОЛ в Якутске — продажа, регистрация в ФНС и сервисное обслуживание.'),
('partner.atol.products', '[{"icon":"CreditCard","name":"Онлайн-кассы","desc":"Фискальные регистраторы и автономные кассы, соответствующие 54-ФЗ. Для розницы, HoReCa и сферы услуг."},{"icon":"ScanBarcode","name":"Терминалы сбора данных","desc":"ТСД серии АТОЛ Smart для автоматизации склада, магазина и производства. Работают под Android, поддерживают 1С и систему маркировки."},{"icon":"Printer","name":"Принтеры этикеток","desc":"Термо и термотрансферные принтеры для печати этикеток, ценников и штрихкодов. Поддержка маркировки Честный Знак."},{"icon":"Wifi","name":"ОФД АТОЛ","desc":"Собственный оператор фискальных данных. Надёжная передача чеков в ФНС, личный кабинет с аналитикой."},{"icon":"Package","name":"Фискальные накопители","desc":"ФН-1.1 и ФН-1.2 на 15 и 36 месяцев. Официальные поставки, гарантия подлинности."},{"icon":"Settings","name":"Сервис и поддержка","desc":"Регистрация ККТ в ФНС, техническое обслуживание, замена ФН и обновление ПО."}]'),
('partner.atol.stats', '[{"value":"20+","label":"лет на рынке"},{"value":"3 млн+","label":"касс работает в России"},{"value":"54-ФЗ","label":"полное соответствие"},{"value":"№1","label":"производитель ККТ в РФ"}]'),
('partner.sbis.hero_title', 'СБИС — автоматизация бизнеса и ЭДО'),
('partner.sbis.hero_desc', 'Официальный партнёр СБИС (Тензор) в Якутске. Подключение ЭДО, сдача электронной отчётности, CRM, бухгалтерия и кадровый учёт под ключ.'),
('partner.sbis.products', '[{"icon":"FileText","name":"Электронный документооборот","desc":"Обмен счетами-фактурами, актами и накладными с контрагентами в электронном виде."},{"icon":"Send","name":"Электронная отчётность","desc":"Отправка отчётов в ФНС, ПФР, ФСС, Росстат и другие ведомства."},{"icon":"Users","name":"CRM и продажи","desc":"Управление клиентской базой, воронка продаж, задачи и напоминания."},{"icon":"UserCheck","name":"Кадры и зарплата","desc":"Ведение кадрового учёта, расчёт зарплаты, электронные трудовые книжки."},{"icon":"ShoppingCart","name":"Торговля и склад","desc":"Учёт товаров, остатков и движения по складу. Работа с маркировкой Честный Знак."},{"icon":"Building2","name":"Бухгалтерия","desc":"Полный бухгалтерский и налоговый учёт в облаке. Автоматические проводки, сверка с ФНС."}]'),
('partner.datamobile.hero_title', 'DataMobile — ПО для автоматизации склада'),
('partner.datamobile.hero_desc', 'Официальный дилер DataMobile в Якутске. Программное обеспечение для терминалов сбора данных: приём, отгрузка, инвентаризация, маркировка.'),
('partner.dreamkas.hero_title', 'Дримкас — онлайн-кассы для бизнеса'),
('partner.dreamkas.hero_desc', 'Официальный партнёр Дримкас в Якутске. Онлайн-кассы для торговли, услуг и доставки. Простая работа с 54-ФЗ, товароучёт и аналитика.'),
('partner.ofd_yandex.hero_title', 'Яндекс ОФД — оператор фискальных данных'),
('partner.ofd_yandex.hero_desc', 'Официальный партнёр Яндекс ОФД в Якутске. Подключение онлайн-кассы к ОФД, передача чеков в ФНС, личный кабинет.'),
('partner.platforma_ofd.hero_title', 'Платформа ОФД — надёжная передача данных'),
('partner.platforma_ofd.hero_desc', 'Официальный партнёр Платформа ОФД в Якутске. Быстрое подключение, стабильная передача фискальных данных в ФНС.'),
('partner.poscenter.hero_title', 'POSCenter — POS-оборудование для торговли'),
('partner.poscenter.hero_desc', 'Официальный партнёр POSCenter в Якутске. Сенсорные моноблоки, кассовые системы и POS-терминалы для розницы, кафе и ресторанов.'),
('partner.onec.hero_title', '1С:Франчайзи — автоматизация под ключ'),
('partner.onec.hero_desc', 'Официальный франчайзи 1С в Якутске. Внедрение, настройка, разработка и сопровождение программ 1С для любого бизнеса.')
